using sv_98c46bf9f0c34173affdf858f81ba2ab.Models;

namespace sv_98c46bf9f0c34173affdf858f81ba2ab.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with tomato sauce, mozzarella, and fresh basil.", 30),
            new(2, "Pasta Carbonara", "Creamy pasta with pancetta, egg yolk, and Pecorino Romano.", 25),
            new(3, "Tiramisu", "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken in a rich, spiced tomato-cream sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach cooked with paneer cubes and aromatic spices.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with marinated meat and saffron.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Sushi Rolls", "Vinegared rice with fresh fish and vegetables wrapped in nori.", 40),
            new(8, "Ramen", "Rich pork-bone broth with wheat noodles, chashu, and a soft-boiled egg.", 120),
            new(9, "Tempura", "Lightly battered and deep-fried shrimp and seasonal vegetables.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Nav
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2 d-inline-block" role="status">Refreshing…</div>
    }

    <div class="mb-3">
        <label class="form-label me-2">Sort by:</label>
        <a href="@GetSortUrl("newest")" class="btn btn-sm @(CurrentSort == "newest" ? "btn-primary" : "btn-outline-primary")">Newest</a>
        <a href="@GetSortUrl("popular")" class="btn btn-sm @(CurrentSort == "popular" ? "btn-primary" : "btn-outline-primary") ms-1">Popular</a>
    </div>

    @if (_recipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <ul class="list-group">
            @foreach (var recipe in GetSortedRecipes())
            {
                <li class="list-group-item">
                    <h5>@recipe.Title</h5>
                    <p class="mb-1">@recipe.Description</p>
                    <small class="text-muted">Prep time: @recipe.PrepTimeMinutes min</small>
                </li>
            }
        </ul>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _error;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private string CurrentSort => string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
        ? "popular"
        : "newest";

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null && _error is null)
        {
            // Only the sort changed (or nothing changed) — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request for the previous cuisine.
        CancelPendingLoad();

        var cts = new CancellationTokenSource();
        _cts = cts;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            // Guard against a stale callback after cancellation.
            if (cts.Token.IsCancellationRequested)
                return;

            _recipes = results;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException)
        {
            // Expected when the user navigated away or changed cuisine.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null)
            return Enumerable.Empty<Recipe>();

        return CurrentSort == "popular"
            ? _recipes.OrderBy(r => r.PrepTimeMinutes)
            : _recipes.OrderByDescending(r => r.Id);
    }

    private string GetSortUrl(string sort)
    {
        return Nav.GetUriWithQueryParameter("sort", sort);
    }

    private void CancelPendingLoad()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingLoad();
    }
}

